framework_css:
/*
   Architecture / Home Builder Portfolio Framework Styles
   Visual style derived from provided SNS layout: modern, warm gold header,
   soft cards, editorial spacing.
*/

:root {
  /* Color system */
  --color-primary-100: #B59543; /* warm muted gold, main header */
  --color-primary-200: #C5A457; /* lighter gold accent */

  --color-secondary-100: #F5F1E6; /* light warm paper */
  --color-secondary-200: #E8E0D0; /* slightly deeper background */

  --color-accent-100: #FFFFFF;

  --color-neutral-900: #111111;
  --color-neutral-800: #333333;
  --color-neutral-500: #888888;
  --color-neutral-200: #E0D8C8; /* soft card border */
  --color-neutral-100: #F7F4ED; /* subtle elevations */

  --color-success: #3BAA5C;
  --color-error: #D64545;
  --color-warning: #E8A23A;
  --color-info: #3F7FBF;

  /* Typography */
  --font-heading: 'Space Grotesk', -apple-system, BlinkMacSystemFont, 'Helvetica Neue', Helvetica, Arial, sans-serif;
  --font-body: 'Work Sans', -apple-system, BlinkMacSystemFont, 'Helvetica Neue', Helvetica, Arial, sans-serif;
  --font-code: 'Source Code Pro', SFMono-Regular, Menlo, Monaco, Consolas, 'Liberation Mono', 'Courier New', monospace;

  --font-size-h1: 32px;
  --font-size-h2: 24px;
  --font-size-h3: 18px;
  --font-size-body: 14px;
  --font-size-small: 12px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale (8px base) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Radii */
  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-pill: 999px;

  /* Shadows approximating soft UI in the design */
  --shadow-card: 0 18px 40px rgba(0, 0, 0, 0.06);
  --shadow-header: 0 2px 8px rgba(0, 0, 0, 0.08);
  --shadow-soft-light: 0 8px 20px rgba(0, 0, 0, 0.04);

  /* Layout */
  --container-max-width: 1160px;
}

/* Global reset-ish */
*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: 100%;
}

body {
  margin: 0;
  min-height: 100vh;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-800);
  background-color: var(--color-secondary-100);
  -webkit-font-smoothing: antialiased;
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover {
  text-decoration: none;
}

button,
input,
select,
textarea {
  font: inherit;
}

/* Layout helpers */

.container {
  max-width: var(--container-max-width);
  margin-inline: auto;
  padding-inline: var(--space-4);
}

.site-main {
  padding-top: var(--space-5);
  padding-bottom: var(--space-6);
}

@media (max-width: 768px) {
  .container {
    padding-inline: var(--space-3);
  }

  .site-main {
    padding-top: var(--space-4);
    padding-bottom: var(--space-5);
  }
}

/* Type scale */

h1,
h2,
h3,
h4 {
  margin: 0 0 var(--space-3);
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.01em;
  color: var(--color-neutral-900);
}

h1 {
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
}

h2 {
  font-size: var(--font-size-h2);
  line-height: var(--line-height-tight);
}

h3 {
  font-size: var(--font-size-h3);
  line-height: var(--line-height-tight);
}

p {
  margin: 0 0 var(--space-2);
}

small {
  font-size: var(--font-size-small);
}

/* Focus styles for accessibility */

:focus-visible {
  outline: 2px solid var(--color-primary-200);
  outline-offset: 3px;
}

/* HEADER -------------------------------------------------------------- */

.site-header {
  position: sticky;
  top: 0;
  z-index: 40;
  background-color: var(--color-primary-100);
  color: var(--color-accent-100);
  box-shadow: var(--shadow-header);
}

.header-inner {
  display: flex;
  align-items: center;
  gap: var(--space-4);
  padding-block: var(--space-3);
}

.brand {
  white-space: nowrap;
}

.brand-link {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  font-size: 16px;
  letter-spacing: 0.04em;
  text-transform: none;
  color: var(--color-accent-100);
}

.brand-link:hover {
  opacity: 0.9;
}

.primary-nav {
  flex: 1 1 auto;
  overflow-x: auto;
}

.primary-nav-list {
  display: flex;
  align-items: center;
  gap: var(--space-3);
  padding: 0;
  margin: 0;
  list-style: none;
}

.primary-nav-item {
  flex: 0 0 auto;
}

.primary-nav-link {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding-inline: 18px;
  padding-block: 8px;
  border-radius: var(--radius-pill);
  border: 1px solid transparent;
  font-size: 13px;
  font-weight: var(--font-weight-medium);
  letter-spacing: 0.04em;
  text-transform: none;
  color: var(--color-secondary-100);
  background-color: transparent;
  transition: background-color 150ms ease, color 150ms ease, box-shadow 150ms ease, border-color 150ms ease;
  white-space: nowrap;
}

.primary-nav-link:hover {
  background-color: rgba(255, 255, 255, 0.14);
}

.primary-nav-link.is-current {
  background-color: var(--color-secondary-100);
  color: var(--color-primary-100);
  box-shadow: var(--shadow-soft-light);
}

@media (max-width: 640px) {
  .header-inner {
    flex-wrap: wrap;
    row-gap: var(--space-2);
  }

  .primary-nav {
    width: 100%;
  }

  .primary-nav-list {
    padding-bottom: 2px;
  }
}

/* FOOTER -------------------------------------------------------------- */

.site-footer {
  border-top: 1px solid var(--color-neutral-200);
  background-color: #151515;
  color: var(--color-secondary-100);
}

.footer-inner {
  padding-block: var(--space-5);
}

.footer-top {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-4);
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: var(--space-4);
}

.footer-brand {
  max-width: 260px;
}

.footer-logo-text {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  font-size: 16px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  margin-bottom: var(--space-2);
}

.footer-tagline {
  margin: 0;
  font-size: 13px;
  color: var(--color-neutral-500);
}

.footer-nav {
  flex: 1 1 280px;
}

.footer-nav-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
  gap: var(--space-2) var(--space-4);
}

.footer-nav-item {}

.footer-nav-link {
  display: inline-flex;
  align-items: center;
  font-size: 13px;
  color: var(--color-secondary-100);
  opacity: 0.9;
  transition: color 150ms ease, opacity 150ms ease, transform 120ms ease;
}

.footer-nav-link::before {
  content: '\2022';
  font-size: 10px;
  margin-right: 6px;
  color: var(--color-primary-200);
}

.footer-nav-link:hover {
  color: var(--color-primary-200);
  opacity: 1;
  transform: translateY(-1px);
}

.footer-bottom {
  border-top: 1px solid rgba(255, 255, 255, 0.06);
  padding-top: var(--space-3);
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: var(--space-2);
}

.footer-meta {
  margin: 0;
  font-size: 12px;
  color: var(--color-neutral-500);
}

@media (max-width: 640px) {
  .footer-inner {
    padding-block: var(--space-4);
  }

  .footer-bottom {
    flex-direction: column;
    align-items: flex-start;
  }
}

/* CARD SYSTEM (for use within #content, matching screenshot style) ----- */

.card-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
  gap: var(--space-4);
}

.card {
  background-color: var(--color-accent-100);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-card);
  border: 1px solid var(--color-neutral-200);
  overflow: hidden;
}

.card-media {
  margin: 0;
}

.card-media img {
  width: 100%;
  height: auto;
  display: block;
}

.card-body {
  padding: var(--space-3);
}

.card-label {
  display: block;
  margin-bottom: var(--space-1);
  font-size: 11px;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--color-primary-200);
  font-weight: var(--font-weight-semibold);
}

.card-title {
  font-family: var(--font-heading);
  font-size: var(--font-size-h3);
  margin-bottom: var(--space-2);
}

.card-meta {
  font-size: 12px;
  color: var(--color-neutral-500);
  margin-bottom: var(--space-2);
}

.card-text {
  font-size: var(--font-size-body);
  color: var(--color-neutral-800);
}

/* Utility classes ----------------------------------------------------- */

.u-text-muted {
  color: var(--color-neutral-500);
}

.u-uppercase {
  text-transform: uppercase;
  letter-spacing: 0.12em;
}

.u-section {
  margin-bottom: var(--space-6);
}

/* Example search / filter shell styling (for optional use in content)
   Mirrors the pill-shaped controls from the design but is not wired to
   any navigation or extra links. */

.search-filter-bar {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-2);
  align-items: center;
  justify-content: flex-end;
  margin-bottom: var(--space-4);
}

.search-field {
  flex: 1 1 220px;
  min-width: 0;
  background-color: var(--color-secondary-200);
  border-radius: var(--radius-pill);
  padding: 8px 14px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.search-field input[type='search'] {
  border: none;
  outline: none;
  background: transparent;
  width: 100%;
  font-size: var(--font-size-body);
  color: var(--color-neutral-800);
}

.search-field input[type='search']::placeholder {
  color: var(--color-neutral-500);
}

.filter-chip {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 8px 14px;
  border-radius: var(--radius-pill);
  background-color: var(--color-secondary-200);
  font-size: var(--font-size-body);
  color: var(--color-neutral-800);
}

.filter-chip::after {
  content: '\25BE'; /* downwards small triangle */
  font-size: 10px;
}

@media (max-width: 640px) {
  .search-filter-bar {
    justify-content: stretch;
  }

  .filter-chip {
    justify-content: center;
  }
}
